const webhookItem = $('Link Webhook').item;
const binary = webhookItem.binary || {};
const binaryKeys = Object.keys(binary);
const hasBinary = binaryKeys.length > 0;
const cookie = $('Get Auth (Webhook)').item.json.cookie;

if (hasBinary) {
  const binaryKey = binaryKeys[0];
  const binaryProp = binary[binaryKey];
  const staticData = $getWorkflowStaticData('global');
  staticData.pendingFile = {
    data: binaryProp.data,
    mimeType: binaryProp.mimeType || 'text/csv',
    fileName: binaryProp.fileName || 'upload.csv',
    cookie
  };
  return [{
    json: {
      hasBinary: true,
      fileName: binaryProp.fileName || 'upload.csv',
      cookie
    }
  }];
}

return [{
  json: { hasBinary: false, fileName: null, cookie }
}];

// Save file to static data if present, even during auth wait
const webhookItem = $('Link Webhook').item;
const binary = webhookItem.binary || {};
const binaryKeys = Object.keys(binary);
if (binaryKeys.length > 0) {
  const binaryProp = binary[binaryKeys[0]];
  const staticData = $getWorkflowStaticData('global');
  staticData.pendingFile = {
    data: binaryProp.data,
    mimeType: binaryProp.mimeType || 'text/csv',
    fileName: binaryProp.fileName || 'upload.csv'
  };
}
return [{json: {status: 'authenticating', message: 'TMLink is logging in via email OTP. This takes about 30 seconds. Please wait…'}}];

const resumeUrl = $execution.resumeUrl.replace('http://localhost:5678', 'http://localhost:3001/n8n').replace('http://n8n:5678', 'http://localhost:3001/n8n');
const webhookBody = $('Link Webhook').item.json.body || {};
const userEmail = webhookBody.userEmail || '';
const approverRaw = webhookBody.approverEmail || '';
const approverEmail = approverRaw || userEmail;
const sameApprover = !approverRaw || approverRaw === userEmail;
let tokenParam = '';
if (!sameApprover) {
  const crypto = require('crypto');
  const approvalToken = crypto.randomBytes(16).toString('hex');
  const staticData = $getWorkflowStaticData('global');
  staticData.approvalToken = approvalToken;
  tokenParam = '&token=' + approvalToken;
} else {
  const staticData = $getWorkflowStaticData('global');
  delete staticData.approvalToken;
}
const approveUrl = resumeUrl + '&approved=true' + tokenParam;
const rejectUrl  = resumeUrl + '&approved=false' + tokenParam;
return [{json: {fileName: $json.fileName, approveUrl, rejectUrl, cookie: $json.cookie, sameApprover, approverEmail}}];

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingFile;
if (!pending) throw new Error('No pending file found in static data.');
const freshCookie = $('Re-Authenticate').item.json.cookie || pending.cookie;
if (!freshCookie) throw new Error('No valid session cookie.');

// Read CSV header and map column names to TMLink API type codes
const csvHeader = Buffer.from(pending.data, 'base64').toString('utf8').split(/\r?\n/)[0];
const cols = csvHeader.split(',').map(c => c.trim().replace(/^\"|\"$/g, '').toLowerCase());

const fnMap = {fname:'fname',first_name:'fname',firstname:'fname',fname_c1:'fname',given_name:'fname',givenname:'fname',forename:'fname'};
const lnMap = {lname:'lname',last_name:'lname',lastname:'lname',lname_c1:'lname',surname:'lname',family_name:'lname',familyname:'lname'};

const fnCode = cols.map(c => fnMap[c]).find(Boolean) || null;
const lnCode = cols.map(c => lnMap[c]).find(Boolean) || null;
const apiCols = [fnCode, lnCode].filter(Boolean);

return [{
  json: { cookie: freshCookie, fileName: pending.fileName, cols: apiCols },
  binary: {
    file: {
      data: pending.data,
      mimeType: pending.mimeType || 'text/csv',
      fileName: pending.fileName || 'upload.csv'
    }
  }
}];

const uploadResult = $('Upload File').item.json;
const groups = uploadResult.matched_groups || {};
const cookie = $('Restore File').item.json.cookie;

// Use actual CSV column names from matched_groups (not type codes)
const firstNameCols = groups.first_name || [];
const lastNameCols = groups.last_name || [];

if (!firstNameCols.length || !lastNameCols.length) {
  throw new Error('CSV missing detectable first or last name columns');
}

let cols = [firstNameCols[0], lastNameCols[0]];

const optionalGroups = ['birth_year','birth_month','birth_day','sex','age','address','zipcode','zip','phone'];
const excludedGroups = new Set(['first_name','last_name','record_id','entity_id']);
for (const [cat, colList] of Object.entries(groups)) {
  if (cols.length >= 10) break;
  if (excludedGroups.has(cat)) continue;
  if (!optionalGroups.includes(cat)) continue;
  const col = colList[0];
  if (col && !cols.includes(col)) cols.push(col);
}

return [{ json: { cookie, cols: cols.slice(0, 10) } }];

const linkResult = $('Run Linkage (After Upload)').item.json;
const err = linkResult.error;
const msg = err
  ? 'Linkage error: ' + (err.message || JSON.stringify(err))
  : (linkResult.Message || linkResult.message || JSON.stringify(linkResult));
const status = err ? 'linkage_error' : 'linkage_done';
return [{json: {status, message: msg, linkage_message: msg}}];

const tls = require('node:tls');
const host = 'smtp.gmail.com';
const port = 465;
const user = $env.SMTP_FROM || '';
const pass = $env.GMAIL_APP_PASSWORD || '';
const webhookBody = $('Link Webhook').item.json.body || {};
const to = webhookBody.approverEmail || webhookBody.userEmail || $env.APPROVER_EMAIL || '';
if (!user || !pass || !to) return [{json: {emailSent: false, reason: 'SMTP not configured or no approver email provided'}}];

const fileName  = $json.fileName  || 'unknown';
const approveUrl = $json.approveUrl || '';
const rejectUrl  = $json.rejectUrl  || '';
const subject = `[TMLink Approval Needed] ${fileName}`;
const body = [
  'A file has been uploaded to TMLink and is awaiting your approval.',
  '',
  'File: ' + fileName,
  '',
  'Open one of these links in your browser (must be on the same machine as TMLink):',
  '',
  'APPROVE: ' + approveUrl,
  'REJECT:  ' + rejectUrl,
  '',
  '-- TMLink Agent'
].join('\r\n');

const msg = [
  'From: TMLink <' + user + '>',
  'To: ' + to,
  'Subject: ' + subject,
  'Date: ' + new Date().toUTCString(),
  'MIME-Version: 1.0',
  'Content-Type: text/plain; charset=UTF-8',
  '',
  body
].join('\r\n');

await new Promise((resolve, reject) => {
  const socket = tls.connect({ host, port, servername: host }, () => {
    let buf = '';
    let step = 0;
    socket.on('data', chunk => {
      buf += chunk.toString();
      const lines = buf.split('\r\n');
      buf = lines.pop();
      for (const line of lines) {
        if (!line) continue;
        const code = parseInt(line.slice(0, 3), 10);
        const last = line[3] !== '-';
        if (!last) continue;
        if (code >= 400) { socket.destroy(); reject(new Error('SMTP: ' + line)); return; }
        switch (step) {
          case 0: if (code === 220) { socket.write('EHLO localhost\r\n'); step++; } break;
          case 1: if (code === 250) { socket.write('AUTH LOGIN\r\n'); step++; } break;
          case 2: if (code === 334) { socket.write(Buffer.from(user).toString('base64') + '\r\n'); step++; } break;
          case 3: if (code === 334) { socket.write(Buffer.from(pass).toString('base64') + '\r\n'); step++; } break;
          case 4: if (code === 235) { socket.write('MAIL FROM:<' + user + '>\r\n'); step++; } break;
          case 5: if (code === 250) { socket.write('RCPT TO:<' + to + '>\r\n'); step++; } break;
          case 6: if (code === 250) { socket.write('DATA\r\n'); step++; } break;
          case 7: if (code === 354) { socket.write(msg + '\r\n.\r\n'); step++; } break;
          case 8: if (code === 250) { socket.write('QUIT\r\n'); step++; } break;
          case 9: if (code === 221) { socket.end(); resolve(); } break;
        }
      }
    });
    socket.on('error', reject);
  });
  socket.on('error', reject);
});

return [{json: {emailSent: true, to, subject}}];

const staticData = $getWorkflowStaticData('global');
const requiredToken = staticData.approvalToken;
if (requiredToken) {
  const providedToken = ($json.query && $json.query.token) || '';
  if (providedToken !== requiredToken) {
    return [{json: {query: {approved: 'false'}, tokenValid: false, reason: 'Invalid approval token'}}];
  }
  delete staticData.approvalToken;
}
return [{json: {query: $json.query, tokenValid: true}}];
